#include<bits/stdc++.h>
using namespace std;
const int N=355;
int n,m,a[N],cnt[10],dp[45][45][45][45];
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n;i++) cin>>a[i];
    while(m--)
    {
        int x;
        cin>>x;
        cnt[x]++;
    }
    dp[0][0][0][0]=a[1];
    for(int i=0;i<=cnt[1];i++)
    {
        for(int j=0;j<=cnt[2];j++)
        {
            for(int k=0;k<=cnt[3];k++)
            {
                for(int k2=0;k2<=cnt[4];k2++)
                {
                    if(i+j+k+k2==0) continue;
                    int pos=i+2*j+3*k+4*k2+1;
                    if(i) dp[i][j][k][k2]=max(dp[i][j][k][k2],dp[i-1][j][k][k2]);
                    if(j) dp[i][j][k][k2]=max(dp[i][j][k][k2],dp[i][j-1][k][k2]);
                    if(k) dp[i][j][k][k2]=max(dp[i][j][k][k2],dp[i][j][k-1][k2]);
                    if(k2) dp[i][j][k][k2]=max(dp[i][j][k][k2],dp[i][j][k][k2-1]);
                    dp[i][j][k][k2]+=a[pos];
                }
            }
        }
    }
    cout<<dp[cnt[1]][cnt[2]][cnt[3]][cnt[4]];
    return 0;
}
